Good, the LLM returned a transform function. Now I'll validate it for safety and execute it in a sandbox.

```repl
# Safety checks
FORBIDDEN_TOKENS = {"exec(", "eval(", "compile(", "__import__", "os.", "subprocess",
                    "open(", "pathlib", "shutil", "sys.", "importlib"}
for token in FORBIDDEN_TOKENS:
    if token in generated_code:
        raise RuntimeError(f"Generated code contains forbidden token: {token}")

# Validate imports via AST
tree = ast.parse(generated_code)
allowed_imports = {"re", "json"}
for node in ast.walk(tree):
    if isinstance(node, ast.Import):
        for alias in node.names:
            if alias.name not in allowed_imports:
                raise RuntimeError(f"Disallowed import: {alias.name}")
    elif isinstance(node, ast.ImportFrom):
        if node.module and node.module.split(".")[0] not in allowed_imports:
            raise RuntimeError(f"Disallowed import: {node.module}")

print("Safety checks passed")

# Exec in sandbox
sandbox = {}
exec(generated_code, sandbox)
transform_fn = sandbox["transform"]

# Apply to all sample records
results = []
for record in sample_records:
    result = transform_fn(record.copy())
    if not isinstance(result, dict):
        raise RuntimeError(f"transform returned {type(result).__name__}, expected dict")
    results.append(result)
    print(f"  {record['vendor_name']:>35} -> {result['vendor_name']}")
    if result.get('suite'):
        print(f"    street={result['street']}, suite={result['suite']}")

transformed_count = len(results)
all_upper = all(r['vendor_name'] == r['vendor_name'].upper() for r in results)
no_suffixes = not any(re.search(r'\b(LLC|Inc|Corp)\b', r['vendor_name'], re.IGNORECASE) for r in results)
print(f"Transformed: {transformed_count}, all_upper={all_upper}, no_suffixes={no_suffixes}")
